import type { CheckoutOptions } from './checkout.js'

const STYLES = `
  .ow-overlay {
    position: fixed; inset: 0; z-index: 999999;
    background: rgba(0,0,0,0.6); backdrop-filter: blur(4px);
    display: flex; align-items: center; justify-content: center;
    padding: 1rem; animation: ow-fadein 0.2s ease;
  }
  .ow-modal {
    background: #fff; border-radius: 16px;
    width: 100%; max-width: 440px; overflow: hidden;
    box-shadow: 0 25px 60px rgba(0,0,0,0.3);
    animation: ow-slidein 0.25s ease;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  }
  .ow-modal[data-theme=dark] { background: #1a1a2e; color: #e0e0e0; }
  .ow-header {
    display: flex; align-items: center; justify-content: space-between;
    padding: 1.25rem 1.5rem; border-bottom: 1px solid #f0f0f0;
  }
  [data-theme=dark] .ow-header { border-color: #2a2a4a; }
  .ow-title { font-size: 1.1rem; font-weight: 700; color: #7c3aed; }
  .ow-close {
    background: none; border: none; cursor: pointer; font-size: 1.25rem;
    color: #888; padding: 0.25rem; border-radius: 6px;
    transition: background 0.15s;
  }
  .ow-close:hover { background: #f5f5f5; }
  [data-theme=dark] .ow-close:hover { background: #2a2a4a; }
  .ow-body { padding: 1.5rem; }
  .ow-amount {
    text-align: center; padding: 1rem;
    background: linear-gradient(135deg, #7c3aed15, #06b6d415);
    border-radius: 12px; margin-bottom: 1.5rem;
  }
  .ow-amount-value { font-size: 2rem; font-weight: 800; color: #7c3aed; }
  .ow-amount-currency { font-size: 1rem; color: #888; margin-left: 0.5rem; }
  .ow-label { font-size: 0.8rem; font-weight: 600; color: #888; text-transform: uppercase; letter-spacing: 0.05em; margin-bottom: 0.5rem; }
  .ow-input {
    width: 100%; padding: 0.75rem 1rem; border: 2px solid #e0e0e0;
    border-radius: 10px; font-size: 1rem; outline: none; box-sizing: border-box;
    transition: border-color 0.15s;
  }
  .ow-input:focus { border-color: #7c3aed; }
  [data-theme=dark] .ow-input { background: #2a2a4a; border-color: #3a3a6a; color: #e0e0e0; }
  .ow-input-group { margin-bottom: 1rem; }
  .ow-otp-hint { font-size: 0.8rem; color: #888; margin-top: 0.4rem; }
  .ow-btn {
    width: 100%; padding: 0.875rem; border: none; border-radius: 10px;
    font-size: 1rem; font-weight: 700; cursor: pointer;
    background: #7c3aed; color: #fff; margin-top: 0.5rem;
    transition: background 0.15s, transform 0.1s;
  }
  .ow-btn:hover { background: #6d28d9; }
  .ow-btn:active { transform: scale(0.98); }
  .ow-btn:disabled { background: #ccc; cursor: not-allowed; transform: none; }
  .ow-btn-ghost {
    background: transparent; color: #888; font-size: 0.9rem; margin-top: 0.5rem;
    text-decoration: underline; border: none; cursor: pointer; width: 100%;
  }
  .ow-error { color: #ef4444; font-size: 0.875rem; margin-top: 0.5rem; text-align: center; }
  .ow-success { color: #22c55e; font-size: 1rem; text-align: center; padding: 1rem; }
  .ow-spinner { display: inline-block; width: 1rem; height: 1rem; border: 2px solid #fff4; border-top-color: #fff; border-radius: 50%; animation: ow-spin 0.7s linear infinite; vertical-align: middle; margin-right: 0.5rem; }
  .ow-footer { padding: 0.75rem 1.5rem; border-top: 1px solid #f0f0f0; text-align: center; font-size: 0.75rem; color: #aaa; }
  [data-theme=dark] .ow-footer { border-color: #2a2a4a; }
  @keyframes ow-fadein { from { opacity: 0 } to { opacity: 1 } }
  @keyframes ow-slidein { from { transform: translateY(24px); opacity: 0 } to { transform: translateY(0); opacity: 1 } }
  @keyframes ow-spin { to { transform: rotate(360deg) } }
`

type Step = 'alias' | 'otp' | 'processing' | 'success' | 'failed'

export class AstroCheckout {
  private options: CheckoutOptions
  private overlay: HTMLElement | null = null
  private styleEl: HTMLElement | null = null
  private step: Step = 'alias'
  private aliasValue = ''
  private errorMsg = ''
  private sessionData: any = null

  constructor(options: CheckoutOptions) {
    this.options = options
  }

  mount(): void {
    this.injectStyles()
    this.render()
  }

  destroy(): void {
    this.overlay?.remove()
    this.styleEl?.remove()
    this.overlay = null
  }

  private injectStyles(): void {
    if (document.getElementById('ow-styles')) return
    this.styleEl = document.createElement('style')
    this.styleEl.id = 'ow-styles'
    this.styleEl.textContent = STYLES
    document.head.appendChild(this.styleEl)
  }

  private render(): void {
    this.overlay?.remove()

    const theme = this.resolveTheme()
    const overlay = document.createElement('div')
    overlay.className = 'ow-overlay'
    overlay.addEventListener('click', (e) => {
      if (e.target === overlay) this.handleDismiss()
    })

    const modal = document.createElement('div')
    modal.className = 'ow-modal'
    modal.setAttribute('data-theme', theme)

    modal.innerHTML = this.renderHTML()
    overlay.appendChild(modal)
    document.body.appendChild(overlay)
    this.overlay = overlay

    this.bindEvents(modal)
    modal.querySelector<HTMLInputElement>('.ow-alias-input')?.focus()
  }

  private renderHTML(): string {
    const amount = this.sessionData?.amount
    const currency = this.sessionData?.currency ?? 'LYD'
    const divisor = currency === 'LYD' ? 1000 : 100
    const decimals = currency === 'LYD' ? 3 : 2
    const displayAmount = amount != null
      ? `<div class="ow-amount"><span class="ow-amount-value">${(amount / divisor).toFixed(decimals)}</span><span class="ow-amount-currency">${currency}</span></div>`
      : ''

    const header = `
      <div class="ow-header">
        <span class="ow-title">Astro Pay</span>
        <button class="ow-close" aria-label="Close">✕</button>
      </div>
    `
    const footer = `<div class="ow-footer">Secured by <strong>Neptune Astro</strong> · OpenWave Standard</div>`

    let body = ''

    if (this.step === 'alias') {
      body = `
        <div class="ow-body">
          ${displayAmount}
          <div class="ow-input-group">
            <div class="ow-label">Pay with</div>
            <input class="ow-input ow-alias-input" type="text" placeholder="your-alias or LY..." value="${this.aliasValue}" autocomplete="off" />
            <div class="ow-otp-hint">Enter your NPT alias (e.g. <strong>mtellesy</strong>) or your IBAN</div>
          </div>
          ${this.errorMsg ? `<div class="ow-error">${this.errorMsg}</div>` : ''}
          <button class="ow-btn ow-pay-btn">Continue →</button>
          <button class="ow-btn-ghost ow-cancel-btn">Cancel</button>
        </div>
      `
    } else if (this.step === 'otp') {
      body = `
        <div class="ow-body">
          ${displayAmount}
          <div class="ow-input-group">
            <div class="ow-label">One-Time Password</div>
            <input class="ow-input ow-otp-input" type="text" inputmode="numeric" maxlength="6" placeholder="000000" autocomplete="one-time-code" />
            <div class="ow-otp-hint">Check your SMS for the OTP sent to your registered number</div>
          </div>
          ${this.errorMsg ? `<div class="ow-error">${this.errorMsg}</div>` : ''}
          <button class="ow-btn ow-confirm-btn">Confirm Payment</button>
          <button class="ow-btn-ghost ow-back-btn">← Change alias</button>
        </div>
      `
    } else if (this.step === 'processing') {
      body = `<div class="ow-body"><div class="ow-success"><span class="ow-spinner"></span>Processing payment…</div></div>`
    } else if (this.step === 'success') {
      body = `<div class="ow-body"><div class="ow-success">✅ Payment successful!</div><button class="ow-btn ow-done-btn" style="margin:0 1.5rem 1.5rem;width:calc(100% - 3rem)">Done</button></div>`
    } else if (this.step === 'failed') {
      body = `<div class="ow-body"><div class="ow-error" style="padding:1rem;font-size:1rem">❌ ${this.errorMsg || 'Payment failed'}</div><button class="ow-btn ow-retry-btn" style="margin:0 1.5rem 1.5rem;width:calc(100% - 3rem)">Try again</button></div>`
    }

    return header + body + footer
  }

  private bindEvents(modal: HTMLElement): void {
    modal.querySelector('.ow-close')?.addEventListener('click', () => this.handleDismiss())
    modal.querySelector('.ow-cancel-btn')?.addEventListener('click', () => this.handleDismiss())
    modal.querySelector('.ow-pay-btn')?.addEventListener('click', () => this.handleAliasContinue(modal))
    modal.querySelector('.ow-alias-input')?.addEventListener('keydown', (e) => {
      if ((e as KeyboardEvent).key === 'Enter') this.handleAliasContinue(modal)
    })
    modal.querySelector('.ow-confirm-btn')?.addEventListener('click', () => this.handleOtpConfirm(modal))
    modal.querySelector('.ow-otp-input')?.addEventListener('keydown', (e) => {
      if ((e as KeyboardEvent).key === 'Enter') this.handleOtpConfirm(modal)
    })
    modal.querySelector('.ow-back-btn')?.addEventListener('click', () => {
      this.step = 'alias'; this.errorMsg = ''; this.render()
    })
    modal.querySelector('.ow-done-btn')?.addEventListener('click', () => this.destroy())
    modal.querySelector('.ow-retry-btn')?.addEventListener('click', () => {
      this.step = 'alias'; this.errorMsg = ''; this.render()
    })
  }

  private async handleAliasContinue(modal: HTMLElement): Promise<void> {
    const input = modal.querySelector<HTMLInputElement>('.ow-alias-input')
    this.aliasValue = input?.value.trim() ?? ''
    if (!this.aliasValue) { this.errorMsg = 'Please enter an alias or IBAN'; this.render(); return }

    const btn = modal.querySelector<HTMLButtonElement>('.ow-pay-btn')!
    btn.disabled = true
    btn.innerHTML = '<span class="ow-spinner"></span>Verifying…'
    this.errorMsg = ''

    try {
      const base = this.options.gatewayUrl ?? ''
      const res = await fetch(`${base}/payments/sessions/${this.options.sessionId}/initiate`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ alias: this.aliasValue }),
      })
      const data = await res.json()
      if (!res.ok) { this.errorMsg = data?.error?.message ?? 'Verification failed'; this.render(); return }
      this.sessionData = { ...this.sessionData, ...data }
      this.step = 'otp'
      this.render()
    } catch {
      this.errorMsg = 'Network error. Please try again.'
      this.render()
    }
  }

  private async handleOtpConfirm(modal: HTMLElement): Promise<void> {
    const otp = modal.querySelector<HTMLInputElement>('.ow-otp-input')?.value.trim() ?? ''
    if (otp.length < 4) { this.errorMsg = 'Please enter a valid OTP'; this.render(); return }

    this.step = 'processing'
    this.render()

    try {
      const base = this.options.gatewayUrl ?? ''
      const res = await fetch(`${base}/payments/sessions/${this.options.sessionId}/confirm`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ otp }),
      })
      const data = await res.json()

      if (!res.ok) {
        this.step = 'failed'
        this.errorMsg = data?.error?.message ?? 'Payment failed'
        this.render()
        this.options.onFailed?.({ session_id: this.options.sessionId, status: 'FAILED', message: this.errorMsg })
        return
      }

      this.step = 'success'
      this.render()
      this.options.onSuccess?.({
        session_id: this.options.sessionId,
        status: 'COMPLETED',
        reference: data.reference,
        receipt_url: data.receipt_url,
      })
    } catch {
      this.step = 'failed'
      this.errorMsg = 'Network error. Please try again.'
      this.render()
    }
  }

  private handleDismiss(): void {
    this.destroy()
    this.options.onDismiss?.()
  }

  private resolveTheme(): 'light' | 'dark' {
    const t = this.options.theme ?? 'auto'
    if (t === 'light') return 'light'
    if (t === 'dark') return 'dark'
    return window.matchMedia?.('(prefers-color-scheme: dark)').matches ? 'dark' : 'light'
  }
}
